#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static void controller_update_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    bool turbidity_stale = false;
    bool level_stale = false;

    if (controller->has_valid_turbidity) {
        uint32_t age_ms = now_ms - controller->last_turbidity_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            turbidity_stale = true;
        }
    }

    if (controller->has_valid_level) {
        uint32_t age_ms = now_ms - controller->last_level_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            level_stale = true;
        }
    }

    if (turbidity_stale || level_stale) {
        controller_set_safe_idle(controller);
    }
}

static void controller_enter_filtering(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = true;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_FILTERING;
    controller->clear_streak_count = 0;
}

static void controller_enter_settling(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SETTLING;
    controller->settling_started_ms = now_ms;
}

static void controller_enter_draining(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = true;
    controller->state = CONTROLLER_STATE_DRAINING;
    controller->clear_streak_count = 0;
}

static void controller_enter_complete(controller_t *controller, uint32_t now_ms)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_COMPLETE;
    controller->clear_streak_count = 0;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_filter_on;
    bool previous_drain_open;
    controller_state_t previous_state;

    if (controller == NULL) {
        return output;
    }

    previous_filter_on = controller->filter_on;
    previous_drain_open = controller->drain_open;
    previous_state = controller->state;

    /* Check sensor timeout on every step */
    controller_update_sensor_timeout(controller, input.now_ms);

    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        {
            controller->has_valid_turbidity = true;
            controller->last_turbidity_ntu = input.turbidity_ntu;
            controller->last_turbidity_ms = input.now_ms;

            /* Check for COMPLETE condition (LEVEL < 15) */
            if (controller->state == CONTROLLER_STATE_COMPLETE) {
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_COMPLETE;
                break;
            }

            /* Update clear streak based on turbidity value */
            if (controller->last_turbidity_ntu <= 35) {
                controller->clear_streak_count++;
            } else {
                controller->clear_streak_count = 0;
            }

            /* Check for FILTERING entry: TURB > 35 AND LEVEL >= 40 */
            if (controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_enter_filtering(controller, input.now_ms);
                    break;
                }
            }

            /* Check for SETTLING entry: clear streak = 3 AND LEVEL >= 40 */
            if (controller->clear_streak_count == CONTROLLER_CLEAR_STREAK_REQUIRED &&
                controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                controller_enter_settling(controller, input.now_ms);
                break;
            }

            /* Check for DRAINING entry during SETTLING */
            if (controller->state == CONTROLLER_STATE_SETTLING) {
                uint32_t settle_elapsed_ms = input.now_ms - controller->settling_started_ms;
                if (settle_elapsed_ms >= CONTROLLER_SETTLING_MS &&
                    controller->last_turbidity_ntu <= 35 &&
                    controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    controller_enter_draining(controller, input.now_ms);
                    break;
                }

                /* Check for disturbance during SETTLING: TURB > 40 */
                if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                    controller->clear_streak_count = 0;
                    controller_enter_filtering(controller, input.now_ms);
                    break;
                }
            }

            /* In FILTERING state, no action needed unless sensor timeout handled above */
            break;
        }

    case CONTROLLER_INPUT_LEVEL:
        {
            controller->has_valid_level = true;
            controller->last_level = input.level;
            controller->last_level_ms = input.now_ms;

            /* Check for COMPLETE condition (LEVEL < 15) */
            if (controller->state == CONTROLLER_STATE_COMPLETE) {
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_COMPLETE;
                break;
            }

            /* Update clear streak based on turbidity value */
            if (controller->has_valid_turbidity) {
                if (controller->last_turbidity_ntu <= 35) {
                    controller->clear_streak_count++;
                } else {
                    controller->clear_streak_count = 0;
                }

                /* Check for FILTERING entry: TURB > 35 AND LEVEL >= 40 */
                if (controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                        controller_enter_filtering(controller, input.now_ms);
                        break;
                    }

                    /* Check for SETTLING entry: clear streak = 3 AND LEVEL >= 40 */
                    if (controller->clear_streak_count == CONTROLLER_CLEAR_STREAK_REQUIRED) {
                        controller_enter_settling(controller, input.now_ms);
                        break;
                    }

                    /* Check for DRAINING entry during SETTLING */
                    if (controller->state == CONTROLLER_STATE_SETTLING) {
                        uint32_t settle_elapsed_ms = input.now_ms - controller->settling_started_ms;
                        if (settle_elapsed_ms >= CONTROLLER_SETTLING_MS &&
                            controller->last_turbidity_ntu <= 35 &&
                            controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                            controller_enter_draining(controller, input.now_ms);
                            break;
                        }

                        /* Check for disturbance during SETTLING: TURB > 40 */
                        if (controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                            controller->clear_streak_count = 0;
                            controller_enter_filtering(controller, input.now_ms);
                            break;
                        }
                    }
                }
            }

            /* Check for COMPLETE condition */
            if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_enter_complete(controller, input.now_ms);
                break;
            }

            break;
        }

    case CONTROLLER_INPUT_SENSOR_TIMEOUT:
    case CONTROLLER_INPUT_INVALID_TURBIDITY:
    case CONTROLLER_INPUT_INVALID_LEVEL:
        /* Invalid input or timeout - go to safe idle */
        controller_set_safe_idle(controller);
        output.timed_out = true;
        break;

    case CONTROLLER_INPUT_NONE:
    default:
        /* No new input - check for sensor timeout and state transitions */
        {
            /* Check for COMPLETE condition */
            if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
                controller_enter_complete(controller, input.now_ms);
                break;
            }

            /* Check for disturbance during DRAINING: TURB > 50 AND LEVEL >= 40 */
            if (controller->state == CONTROLLER_STATE_DRAINING &&
                controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
                controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Close drain, turn filter ON, reset clear streak, return to FILTERING */
                controller->filter_on = true;
                controller->drain_open = false;
                controller->clear_streak_count = 0;
                controller->state = CONTROLLER_STATE_FILTERING;
                break;
            }

            /* Check for disturbance during SETTLING: TURB > 40 */
            if (controller->state == CONTROLLER_STATE_SETTLING &&
                controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
                controller->clear_streak_count = 0;
                controller_enter_filtering(controller, input.now_ms);
                break;
            }

            /* Check for DRAINING entry during SETTLING */
            if (controller->state == CONTROLLER_STATE_SETTLING) {
                uint32_t settle_elapsed_ms = input.now_ms - controller->settling_started_ms;
                if (settle_elapsed_ms >= CONTROLLER_SETTLING_MS &&
                    controller->has_valid_turbidity && controller->last_turbidity_ntu <= 35 &&
                    controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                    controller_enter_draining(controller, input.now_ms);
                    break;
                }
            }

            /* Check for FILTERING entry: TURB > 35 AND LEVEL >= 40 */
            if (controller->has_valid_turbidity && controller->has_valid_level &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    controller_enter_filtering(controller, input.now_ms);
                    break;
                }

                /* Check for SETTLING entry: clear streak = 3 AND LEVEL >= 40 */
                if (controller->clear_streak_count == CONTROLLER_CLEAR_STREAK_REQUIRED) {
                    controller_enter_settling(controller, input.now_ms);
                    break;
                }
            }

            /* In SAFE_IDLE, stay there until both sensors valid */
            break;
        }
    }

    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_filter_on != controller->filter_on) ||
        (previous_drain_open != controller->drain_open) ||
        (previous_state != controller->state);

    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILTERING:
        return "STATE FILTERING";
    case CONTROLLER_STATE_SETTLING:
        return "STATE SETTLING";
    case CONTROLLER_STATE_DRAINING:
        return "STATE DRAINING";
    case CONTROLLER_STATE_COMPLETE:
        return "STATE COMPLETE";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

