cat > /tmp/test_logic.c << 'EOF'
#include <stdio.h>
#include <stdint.h>
#include <stdbool.h>

#define CONTROLLER_CLEAR_THRESHOLD_NTU 35
#define CONTROLLER_SETTLING_RESET_THRESHOLD_NTU 40
#define CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU 50
#define CONTROLLER_MIN_PROCESS_LEVEL 40
#define CONTROLLER_COMPLETE_LEVEL 15
#define CONTROLLER_CLEAR_STREAK_REQUIRED 3
#define CONTROLLER_SETTLING_MS 400U
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TURBIDITY,
    CONTROLLER_INPUT_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_IDLE = 0,
    CONTROLLER_STATE_FILTERING,
    CONTROLLER_STATE_SETTLING,
    CONTROLLER_STATE_DRAINING,
    CONTROLLER_STATE_COMPLETE,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int turbidity_ntu;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool filter_on;
    bool drain_open;
    controller_state_t state;
    bool has_valid_turbidity;
    int last_turbidity_ntu;
    uint32_t last_turbidity_ms;
    bool has_valid_level;
    int last_level;
    uint32_t last_level_ms;
    int clear_streak_count;
    uint32_t settling_started_ms;
} controller_t;

void controller_init(controller_t *controller) {
    if (controller == NULL) return;
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

void controller_update_sensor_timeout(controller_t *controller, uint32_t now_ms) {
    bool turbidity_stale = false;
    bool level_stale = false;

    if (controller->has_valid_turbidity) {
        uint32_t age_ms = now_ms - controller->last_turbidity_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) turbidity_stale = true;
    }

    if (controller->has_valid_level) {
        uint32_t age_ms = now_ms - controller->last_level_ms;
        if (age_ms > CONTROLLER_SENSOR_TIMEOUT_MS) level_stale = true;
    }

    if (turbidity_stale || level_stale) {
        controller->filter_on = false;
        controller->drain_open = false;
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
    }
}

void controller_step(controller_t *controller, controller_input_t input) {
    printf("STEP: state=%d(%s), has_valid_turbidity=%d, has_valid_level=%d, last_turb=%d, last_level=%d\n",
           controller->state,
           controller->state == CONTROLLER_STATE_SAFE_IDLE ? "SAFE_IDLE" :
           controller->state == CONTROLLER_STATE_FILTERING ? "FILTERING" :
           controller->state == CONTROLLER_STATE_SETTLING ? "SETTLING" :
           controller->state == CONTROLLER_STATE_DRAINING ? "DRAINING" : "COMPLETE",
           controller->has_valid_turbidity,
           controller->has_valid_level,
           controller->last_turbidity_ntu,
           controller->last_level);

    /* Update timestamps */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    }

    /* Check timeout */
    controller_update_sensor_timeout(controller, input.now_ms);

    /* Process input */
    switch (input.kind) {
    case CONTROLLER_INPUT_TURBIDITY:
        if (controller->state == CONTROLLER_STATE_COMPLETE) {
            break;
        }

        /* Update streak */
        if (input.turbidity_ntu <= 35) {
            controller->clear_streak_count++;
            printf("  Streak incremented to %d\n", controller->clear_streak_count);
        } else {
            controller->clear_streak_count = 0;
            printf("  Streak reset to 0\n");
        }

        /* Check FILTERING */
        if (controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            if (input.turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                printf("  Entering FILTERING\n");
                controller->filter_on = true;
                controller->drain_open = false;
                controller->state = CONTROLLER_STATE_FILTERING;
                break;
            }
        }

        /* Check SETTLING */
        if (controller->clear_streak_count == CONTROLLER_CLEAR_STREAK_REQUIRED &&
            controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            printf("  Entering SETTLING\n");
            controller->filter_on = false;
            controller->drain_open = false;
            controller->state = CONTROLLER_STATE_SETTLING;
            break;
        }
        break;

    case CONTROLLER_INPUT_LEVEL:
        if (controller->state == CONTROLLER_STATE_COMPLETE) {
            break;
        }

        /* Update streak */
        if (controller->has_valid_turbidity) {
            if (input.turbidity_ntu <= 35) {
                controller->clear_streak_count++;
                printf("  Streak incremented to %d\n", controller->clear_streak_count);
            } else {
                controller->clear_streak_count = 0;
                printf("  Streak reset to 0\n");
            }

            /* Check FILTERING/SETTLING */
            if (input.level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    printf("  Entering FILTERING\n");
                    controller->filter_on = true;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_FILTERING;
                    break;
                }
                if (controller->clear_streak_count == CONTROLLER_CLEAR_STREAK_REQUIRED) {
                    printf("  Entering SETTLING\n");
                    controller->filter_on = false;
                    controller->drain_open = false;
                    controller->state = CONTROLLER_STATE_SETTLING;
                    break;
                }
            }
        }
        break;
    }

    printf("  Output: state=%d(%s)\n",
           controller->state,
           controller->state == CONTROLLER_STATE_SAFE_IDLE ? "SAFE_IDLE" :
           controller->state == CONTROLLER_STATE_FILTERING ? "FILTERING" :
           controller->state == CONTROLLER_STATE_SETTLING ? "SETTLING" :
           controller->state == CONTROLLER_STATE_DRAINING ? "DRAINING" : "COMPLETE");
}

int main() {
    controller_t ctrl;
    controller_init(&ctrl);

    printf("=== Send LEVEL 50 ===\n");
    controller_step(&ctrl, (controller_input_t){.kind=CONTROLLER_INPUT_LEVEL, .level=50, .now_ms=100});

    printf("\n=== Send TURB 50 ===\n");
    controller_step(&ctrl, (controller_input_t){.kind=CONTROLLER_INPUT_TURBIDITY, .turbidity_ntu=50, .level=0, .now_ms=200});

    return 0;
}
